+/// Benchmark: Precision allocation lookup and decision
+fn bench_precision_allocation(c: &mut Criterion) {
+    let mut group = c.benchmark_group("precision_allocation");
+
+    #[derive(Debug, Clone, Copy, PartialEq)]
+    #[repr(u8)]
+    enum Precision {
