+                let mut router = MemoryAwareRouter::with_default_affinity(config).unwrap();
+
+                let resident: Vec<usize> = (0..n / 2).collect();
+                router.update_cache_state(&resident);
+
+                // Generate batch of 8 tokens
+                let batch_logits: Vec<Vec<f32>> = (0..8)
