+        let top_2 = affinity.top_k_by_frequency(2);
+        assert_eq!(top_2.len(), 2);
+        // Expert 2 activated 3 times, highest
+        assert_eq!(top_2[0], 2);
+        // Expert 1 activated 2 times, second
+        assert_eq!(top_2[1], 1);
+    }
