+        assert_eq!(config.num_experts, 8);
+        assert!((config.decay - 0.99).abs() < 1e-6);
+        assert!((config.activation_boost - 1.0).abs() < 1e-6);
+        assert!((config.max_score - 1.0).abs() < 1e-6);
+    }
