+        let config = PrecisionConfig {
+            hot_percentile: 0.8,
+            cold_percentile: 0.2,
+            ..Default::default()
+        };
+        let mut allocator = PrecisionAllocator::new(4, config).unwrap();
+
+        // Set up activation counts: 100, 75, 25, 5
+        for _ in 0..100 {
+            allocator.record_activation(0);
